var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>으, 으아아아아아아아아아아악!!</color>","JPN":"<color=#ff3636>う、うわああああああああああ！！</color>","ENG":"<color=#ff3636>AAAAAARRRRRGH!!</color>","TWN":"<color=#ff3636>呃，呃啊啊啊啊啊啊啊啊啊啊啊！！</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L3_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>인가아안! 이 버러지 같은 인간 놈들이이이이!</color>","JPN":"<color=#ff3636>人間！！！　この虫けらのような人間どもが！！！！！</color>","ENG":"<color=#ff3636>HUMAAAN! You worthless maggots!!</color>","TWN":"<color=#ff3636>怎麼可能！你們這些如同螞蟻般的人類！</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_45"},{"id":"L5_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"해, 해냈어!","JPN":"や、やったわ！","ENG":"W-we did it!","TWN":"成，成功了！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"방금, 아이기스의 주포로 아포리아의 핵이 노출됐어!","JPN":"今、アイギスの主砲を食らってアポリアの核が剥き出しになったわ！","ENG":"Aegis's cannon just exposed Aporia's core!","TWN":"剛剛，埃癸斯的主炮讓阿波利亞露出了核心！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"좋아! 지금이야! 모두 아포리아 흉부의 핵을 노려서 쏴버려!","JPN":"よし！　今だ！　みんなアポリアの胸部にある核を狙って撃て！","ENG":"All right! Now's our chance! Everyone, aim for the core in Aporia's chest!","TWN":"很好！就是現在！全體瞄準阿波利亞胸部的核心進行射擊！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"소령! 이제 한 발짝이야! 한 발짝만 더 가면 아포리아를 쓰러트릴 수 있다고!","JPN":"少佐！　あと一歩よ！　あと一歩でアポリアを倒せるわ！","ENG":"Major! We're getting close! One more step and we can defeat Aporia!","TWN":"少校！現在只差一步！再加把勁兒就能打倒阿波利亞了！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L15_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"소령?","JPN":"少佐？","ENG":"Major?","TWN":"少校？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>SYSTEM 경고, CRF 잔량이 부족합니다.</color>","JPN":"<color=#ffd34c>SYSTEM 警告、CRF残量が不足しています。</color>","ENG":"<color=#ffd34c>SYSTEM Warning! Insufficient CRF.</color>","TWN":"<color=#ffd34c>系統警告，CRF殘量不足。</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>SYSTEM 최소 CRF 잔량 보존을 위해 전술 무장을 해제합니다.</color>","JPN":"<color=#ffd34c>SYSTEM 最小CRF残量の保存のために戦術武装を解除します。</color>","ENG":"<color=#ffd34c>SYSTEM Disarming Tactical Gear to retain minimal CRF.</color>","TWN":"<color=#ffd34c>為保持CRF殘量，將強制解除戰術裝備。</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L21_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"소령! 정신 차려, 소령!","JPN":"少佐！　しっかりしろ、少佐！","ENG":"Major! Snap out of it, Major!","TWN":"少校！醒醒，少校！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L22_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"무리야, 한 번에 너무 과도한 연산을 처리해서 뇌에 쇼크가 걸린 거야!","JPN":"無理だ、一度に膨大な量の演算を処理したせいで、脳がショック状態になったんだ！","ENG":"It's too much for her. Her brain is in shock from the overwhelming amount of calculations!","TWN":"沒用！她一次處理過多運算導致大腦休克了！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"쉬게 해야 해!","JPN":"休ませないと！","ENG":"Let her rest!","TWN":"只能讓她休息了！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"하필! 앞으로 한 발짝이었는데!","JPN":"そんな！　あともう一歩だったのに！","ENG":"Geez! Just when we're this close!","TWN":"偏偏是這種時候！就差一步了！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"제길! 녀석이 갑피를 회복하기 전에 어떻게든 해야 해!","JPN":"くそ！　奴が甲皮を再生する前に、なんとかしねえと！","ENG":"Dammit! We gotta get it before its armor regenerates!","TWN":"可惡！必須要在那傢伙的外殼恢復之前做點什麼！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L27_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"내 자력으로 녀석의 전기 방출을 상쇄할게! 그 틈에 빨리 방법을 찾으라고!","JPN":"オレの磁力で奴の電気放出を相殺する！　その隙に早く方法を見つけるんだ！","ENG":"I'll use my magnetic force to neutralize its electricity! Find a way to defeat it in the meantime!","TWN":"我用磁力抵消他釋放的電力！你們把握時間快想點辦法！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"모두 소령님을 둘러 싸! 아포리아의 접근을 막아!","JPN":"全員少佐を囲め！　アポリアを近づかせるな！","ENG":"Everyone, protect the major! Don't let Aporia get close to her!","TWN":"所有人把少校圍起來！阻止阿波利亞的接近！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L33_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"소령님을 반드시 지켜야 한다!","JPN":"なんとしてでも少佐を守れ！","ENG":"We must protect the Major at all costs!","TWN":"一定要保護好少校！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L35_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>감히, 감히 왕이 될 이 몸에게 이런 치욕을!</color>","JPN":"<color=#ff3636>よくも、よくも、王となる身の俺にこんな屈辱を！</color>","ENG":"<color=#ff3636>How dare you humiliate the future king!</color>","TWN":"<color=#ff3636>大膽，你們竟敢如此羞辱即將為王的我！</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>용서 못한다! 이 성가신 인간 놈들!</color>","JPN":"<color=#ff3636>許せん！　このめんどくさい人間ども！</color>","ENG":"<color=#ff3636>Unacceptable! You annoying, puny humans!</color>","TWN":"<color=#ff3636>不可饒恕！你們這些煩人的東西！</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>이 자리에서, 단 한 마리도 남김없이……!</color>","JPN":"<color=#ff3636>今ここで、一匹残らず……！</color>","ENG":"<color=#ff3636>I will kill every last one of–</color>","TWN":"<color=#ff3636>就在這裡，一個不留……！</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>크윽! 네 놈은……!</color>","JPN":"<color=#ff3636>くっ！　貴様は……！</color>","ENG":"<color=#ff3636>Kgh! You...!</color>","TWN":"<color=#ff3636>呃！你這傢伙……！</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"일어나!! 카린!!","JPN":"起きて！！　カリン！！","ENG":"Get up!! Karin!!","TWN":"醒醒！！卡琳！！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"네가 보여주고 싶었던 건……!","JPN":"あなたが見せたかったのは……！","ENG":"What you wanted to show us...!","TWN":"你想給我們看的……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"네가 우리에게 보여주고 싶었던 풍경은 이런 게 아니잖아!!","JPN":"あなたが見せたかった景色はこんなんじゃないでしょ！！","ENG":"I know this isn't what you wanted to show us at all!!","TWN":"你想給我們看的風景可不是這樣的！！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"첫 실전부터 그렇게 꼴사나운 모습을 보이다니!","JPN":"初の実戦からこんなにみっともない姿を見せてしまうなんて！","ENG":"I can't believe I embarrassed myself like that on my first mission!","TWN":"第一次實戰竟然就那麼狼狽！"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_FIRE_SMALL_02"},{"id":"L1_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"다른 대원들의 발목을 붙잡을 수는 없어. 하루라도 빨리 내 실력을 인정받아야 해.","JPN":"他の隊員たちの足かせになるわけにはいかないわ。一日も早く実力で認められなくちゃ。","ENG":"I mustn't slow down the others. I need to prove my worth as soon as possible.","TWN":"不能拖累其他隊員，我必須盡快提升實力。"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그러기 위해서는 1분 1초도 헛되이 쓸 수 없어.","JPN":"そのためには1分1秒も無駄にはできない。","ENG":"To do that, I can't let even a second go to waste.","TWN":"因此，一分一秒也不容浪費。"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_QM","text":{"KOREA":"어깨에 힘이 너무 많이 들어가 있군, 대위.","JPN":"肩に力が入りすぎているぞ、大尉。","ENG":"Captain, you're stressing too much about this.","TWN":"你太過緊繃了，大尉。"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_QM","text":{"KOREA":"그래서는 가만히 있는 표적도 달아나겠어.","JPN":"それでは止まっている標的すら逃げてしまうぞ。","ENG":"At this rate, even still targets are going to run away from you.","TWN":"這種姿勢，靜止的目標你都打不中。"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"제이크 워커 소령님?","JPN":"ジェイク・ウォーカー少佐？","ENG":"Major Jake Walker?","TWN":"傑克·沃克少校？"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"열심히 하랬다고, 첫날부터 이렇게 늦은 시간까지 사격장에 있을 줄이야.","JPN":"頑張れとは言ったが、初日からこんなに遅い時間まで射撃場にいるとはな。","ENG":"Didn't think you'd be at the shooting range this late on your first day after I told you to train harder.","TWN":"居然從第一天開始就在射擊場待到這麼晚，還真是拼命。"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"대위, 자네 평소에 융통성이 없다는 소리를 듣지 않나?","JPN":"大尉、君は普段、融通が利かないと言われることはないか？","ENG":"Captain, people tell you that you're stubborn like an ox, don't they?","TWN":"大尉，平時有沒有人說過你很固執？"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"죄, 죄송합니다. 소령님.","JPN":"も、申し訳ありません。少佐。","ENG":"M-my apologies, Major.","TWN":"非，非常抱歉。少校。"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"후후, 뭐 혼내려던 건 아니니까 안심해.","JPN":"ふふ、まぁ怒るつもりはないから、安心してくれ。","ENG":"Ha ha, at ease. I'm not here to scold you.","TWN":"哈哈，放心，我不是在訓你。"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"난 어렸을 때, 군인이었던 할아버지께 사격을 배웠지.","JPN":"俺は幼い頃、軍人だった祖父から射撃を教わったんだ。","ENG":"I learned to shoot from my grandfather when he was a soldier.","TWN":"我小的時候，跟著軍人出身的爺爺學習射擊。"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그럼, 할아버지께 배운 요령을 알려주도록 할까?","JPN":"さて、祖父から習ったコツを伝授するとしようか？","ENG":"Now then, maybe I'll share some of his secrets to you.","TWN":"想不想知道我從爺爺那學來的訣竅？"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"워, 워커 소령님!?","JPN":"ウォ、ウォーカー少佐！？","ENG":"M-Major Walker?!","TWN":"少，少校？！"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"조바심 내지 마, 대위. 호흡을 가다듬어.","JPN":"焦るな、大尉。呼吸を整えろ。","ENG":"Be patient, Captain. Control your breathing.","TWN":"別著急，大尉，調整一下呼吸。"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"끈질기게 표적을 응시하고, 자기도 모르게 방아쇠를 당겨.","JPN":"相手を凝視して粘り続け、自分でも知らず知らずのうちに引き金を引くんだ。","ENG":"Don't let your target out of your sight, and pull the trigger unconsciously.","TWN":"專注地盯著目標，然後想像自己下意識地扣動扳機。"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"거기에 감정 따위는 필요 없어.","JPN":"感情が入る必要はない。","ENG":"There are no emotions.","TWN":"不要帶任何的情緒。"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"명심해, 카린 웡 대위.","JPN":"よく聞け、カリン・ウォン大尉。","ENG":"Keep that in mind, Captain Karin Wong.","TWN":"記住，卡琳大尉。"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"narration","speaker":null,"text":{"KOREA":"군인이라면, 임무를 위해 마지막까지 냉철함을 유지하는 거야.","JPN":"軍人たるもの任務のために、最後まで冷静さを保て。","ENG":"We soldiers must remain cool-headed while on our missions.","TWN":"身為軍人，為了任務要始終保持冷靜。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>어……?</color>","JPN":"<color=#ff3636>あ……？</color>","ENG":"<color=#ff3636>Huh...?</color>","TWN":"<color=#ff3636>嗯……？</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>카…… 린……?</color>","JPN":"<color=#ff3636>か……りん……？</color>","ENG":"<color=#ff3636>Ka... rin...?</color>","TWN":"<color=#ff3636>卡……琳……？</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"쓰, 쓰러트렸어! 쓰러트렸다고!","JPN":"た、倒した！　倒したわ！","ENG":"W-we did it! It's down!","TWN":"成，成功了！我們打敗他了！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"소령이 핵을 맞췄어!","JPN":"少佐が核を撃った！","ENG":"Major shot its core!","TWN":"少校擊中核心了！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"어이…… 소령?","JPN":"おい……少佐……？","ENG":"Hey... Major?","TWN":"嗯……少校？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"……흐윽.","JPN":"……ふぐっ。","ENG":"...*Sniffle*","TWN":"……嗚嗚。"},"stage":{"bg":"EXILER_05","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"죄송해요, 죄송해요…… 대령님.","JPN":"ごめんなさい、ごめんなさい……大佐。","ENG":"I'm sorry... I'm so sorry, Colonel.","TWN":"對不起，對不起……上校。"},"stage":{"bg":"EXILER_05","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"제가 조금 더 빨리 눈치챘었어야 했는데.","JPN":"もう少し早く気づくべきでした。","ENG":"I should've noticed that it was you sooner.","TWN":"我應該更早一點發現的。"},"stage":{"bg":"EXILER_05","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"흐윽……! 더 일찍 보내드렸어야 했는데……!","JPN":"ふぐっ……！　もう少し早く、眠らせてさしあげるべきだったのに……！","ENG":"Hngh...! I should've given you the rest you needed earlier...!","TWN":"嗚……嗚嗚……！應該更早一點就讓你……！"},"stage":{"bg":"EXILER_05","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"끄윽, 당신은 죽어서까지도 임무를 포기하지 않았는데……!","JPN":"くうっ、あなたは死んだ後も、任務を諦めなかったのに……！","ENG":"*Sob* You didn't give up on your mission even after death...!","TWN":"嗚……你甚至在死後也沒有放棄任務……！"},"stage":{"bg":"EXILER_05","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"저는 당신과 관련된 일에는…… 냉철함을 유지할 수 없었어요.","JPN":"私はあなたが関わっているとなると……冷静さを保つことができませんでした。","ENG":"When it comes to you... I can't seem to remain cool-headed.","TWN":"我在與你有關的事情上……沒辦法保持冷靜。"},"stage":{"bg":"EXILER_05","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"당신의 손에…… 너무 많은 피를 묻게 했어.","JPN":"あなたの手を……血で汚させすぎた。","ENG":"I've allowed... too much blood on your hands.","TWN":"你的手上……沾了太多血了。"},"stage":{"bg":"EXILER_05","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"그러니까…….","JPN":"だから……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"EXILER_05","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"그러니까, 이젠 편히 쉬어도 괜찮아요.","JPN":"だから……もうゆっくりお休みになってください。","ENG":"So now, you can finally rest in peace.","TWN":"所以…現在就安心休息吧。"},"stage":{"bg":"EXILER_06","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_DELTA_CA_KYLE_AP_EXILER_VOICE_9"},{"id":"L4_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"대령님.","JPN":"大佐。","ENG":"Colonel.","TWN":"上校。"},"stage":{"bg":"EXILER_06","bgm":"THEMA_CA_DELTA_KYLE_AP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_DELTA_CA_KYLE_AP_EXILER_VOICE_10"}]`);export{e as default};